	/* ------------------------------------ Template 函数库 ------------------------------------ */
	/*
		依赖项：
			File 函数库
			Array 函数库
			Point Array 函数库
			Dict 函数库
			List 函数库
			Value 函数库
			JNUM 函数库
	*/
	
	typedef struct XTE_Engine_Struct* xteengine;
	typedef struct XTE_Template_Struct* xtetemplate;
	typedef struct XTE_RenderCtx_Struct XTE_RenderCtx;
	typedef struct XTE_StmtParseCtx_Struct XTE_StmtParseCtx;
	typedef struct XTE_StmtRenderCtx_Struct XTE_StmtRenderCtx;
	typedef struct XTE_FuncCtx_Struct XTE_FuncCtx;
	#define XTE_NODE_TEXT					1
	#define XTE_NODE_OUTPUT					2
	#define XTE_NODE_INLINE_BOOL			3
	#define XTE_NODE_STATEMENT				4
	#define XTE_EXPR_PATH					1
	#define XTE_EXPR_TEXT					2
	#define XTE_EXPR_INT					3
	#define XTE_EXPR_BOOL					4
	#define XTE_EXPR_BOOL_EXPR				5
	#define XTE_OUTPUT_TEXT					1
	#define XTE_OUTPUT_NUM					2
	#define XTE_OUTPUT_TIME					3
	#define XTE_OUTPUT_FUNC					4
	#define XTE_STMT_INLINE					0x0001
	#define XTE_STMT_BLOCK					0x0002
	#define XTE_STMT_HYBRID					(XTE_STMT_INLINE | XTE_STMT_BLOCK)
	#define XTE_STMT_RAW_BODY				0x0004
	#define XTE_STMT_ALLOW_NAMED_ARGS		0x0008
	typedef struct {
		int iCode;
		const char* sDesc;
		uint32 iLine;
		uint32 iColumn;
		uint32 iPos;
		uint32 iRefLine;
		uint32 iRefColumn;
		uint32 iRefPos;
	} XTE_Error;
	typedef struct {
		int (*procWrite)(void* pUserData, const char* sText, size_t iSize);
		void* pUserData;
		size_t iWritten;
	} XTE_Writer;
	typedef struct {
		const char* sBracket;
		uint32 iFlags;
	} XTE_ParseOptions;
	typedef struct {
		xvalue pRoot;
		xvalue pCurrent;
		xvalue pGlobal;
		xdict pIncludeMap;
		XTE_Writer* pWriter;
		uint32 iFlags;
	} XTE_RenderOptions;
	typedef struct {
		uint32 iStart;
		uint32 iCount;
	} XTE_NodeSpan;
	typedef struct {
		uint32 iType;
		uint32 iFlags;
		uint32 iTextOff;
		uint32 iTextSize;
		int64 iIntValue;
		int iBoolValue;
	} XTE_ExprNode;
	typedef struct {
		uint32 iNameOff;
		uint32 iNameSize;
		uint32 iRawOff;
		uint32 iRawSize;
		uint32 iFlags;
		uint32 iExprIndex;
	} XTE_ArgItem;
	typedef struct {
		xtetemplate hTemplate;
		const XTE_ArgItem* pItems;
		uint32 iCount;
	} XTE_ArgList;
	typedef struct {
		uint32 iType;
		uint32 iFlags;
		uint32 iPos;
		uint32 iSize;
		union {
			struct {
				uint32 iTextOff;
				uint32 iTextSize;
			} Text;
			struct {
				uint32 iOutputType;
				uint32 iExprIndex;
				uint32 iFormatOff;
				uint32 iFormatSize;
				uint32 iNameOff;
				uint32 iNameSize;
				uint32 iArgStart;
				uint32 iArgCount;
			} Output;
			struct {
				uint32 iExprIndex;
				uint32 iTrueOff;
				uint32 iTrueSize;
				uint32 iFalseOff;
				uint32 iFalseSize;
			} InlineBool;
			struct {
				uint32 iStmtNameOff;
				uint32 iStmtNameSize;
				uint32 iArgStart;
				uint32 iArgCount;
				XTE_NodeSpan tBody;
				uint32 iRawBodyOff;
				uint32 iRawBodySize;
				ptr pData;
			} Statement;
		} Data;
	} XTE_Node;
	typedef enum {
		XTE_FLOW_OK = 0,
		XTE_FLOW_BREAK = 1,
		XTE_FLOW_CONTINUE = 2,
		XTE_FLOW_ERROR = -1
	} XTE_Flow;
	typedef struct XTE_StatementDef_Struct {
		const char* sName;
		uint32 iFlags;
		uint16 iMinArgs;
		uint16 iMaxArgs;
		void* pUserData;
		int (*procParse)(XTE_StmtParseCtx* pCtx, void** ppData);
		XTE_Flow (*procRender)(XTE_StmtRenderCtx* pCtx);
		void (*procFreeData)(void* pData);
	} XTE_StatementDef;
	typedef struct XTE_FunctionDef_Struct {
		const char* sName;
		uint16 iMinArgs;
		uint16 iMaxArgs;
		void* pUserData;
		int (*procCall)(XTE_FuncCtx* pCtx, xvalue* ppRet);
	} XTE_FunctionDef;
	struct XTE_StmtParseCtx_Struct {
		xteengine hEngine;
		xtetemplate hTemplate;
		const XTE_StatementDef* pDef;
		const XTE_ArgList* pArgs;
		const XTE_NodeSpan* pBody;
		const char* sRawBody;
		size_t iRawBodySize;
		XTE_Error* pError;
		void* pUserData;
	};
	struct XTE_StmtRenderCtx_Struct {
		XTE_RenderCtx* pRender;
		const XTE_StatementDef* pDef;
		const XTE_ArgList* pArgs;
		const XTE_NodeSpan* pBody;
		const char* sRawBody;
		size_t iRawBodySize;
		void* pData;
		void* pUserData;
	};
	struct XTE_FuncCtx_Struct {
		XTE_RenderCtx* pRender;
		const XTE_FunctionDef* pDef;
		const XTE_ArgList* pArgs;
		void* pUserData;
	};
