{
	size_t iOff = 0u;
	if ( pOutLen ) { *pOutLen = 0u; }
	if ( sOut == NULL || iOutCap == 0u || (sText == NULL && iLen != 0u) ) { return false; }
	sOut[0] = '\0';
	if ( !__xrtHttpUtilAppendQuotedString(sOut, iOutCap, &iOff, sText, iLen) ) { return false; }
	if ( pOutLen ) { *pOutLen = iOff; }
	return true;
}
