			return (int)syscall(SYS_io_uring_register, hRingFd, iOpcode, pArg, iNrArgs);
		#elif defined(__NR_io_uring_register)
			return (int)syscall(__NR_io_uring_register, hRingFd, iOpcode, pArg, iNrArgs);
