	__xrt_x25519_limb swap = 0;
	__xrt_x25519_limb *x2 = xs[0], *x3 = xs[2], *z3 = xs[3];
	
	memset(xs, 0, 4 * sizeof(__xrt_x25519_fe));
	x2[0] = z3[0] = 1;
	for ( i = 0; i < __XRT_X25519_NLIMBS; i++ ) {
		x3[i] = x1_limbs[i] = __XRT_MG_U32(x1[i * 4 + 3], x1[i * 4 + 2], x1[i * 4 + 1], x1[i * 4]);
	}
	
