// 获取本机名称 （ 需使用 xrtFree 释放 ）
str xrtGetLocalName()
{
	char sLocalName[260];
	if ( gethostname(sLocalName, 260) == 0 ) {
		return xrtCopyStr((str)sLocalName, 0);
	}
	return xCore.sNull;
}
