	__xrtMemDebugLeaveSiteScope(&tScope);
	xrtOwnerEndMutable(&objMM->Owner);
	__xrtMemDebugUnregisterObject(objMM, XRT_MEMDEBUG_OBJECT_FSMEMPOOL, sFile, iLine);
